REVIEW: Nightly backup script for our small prod box. It has set -e at the top so failures abort, and it's been green for weeks:

#!/bin/bash
set -euo pipefail

backup() {
    local archive=$(tar -czf - /var/lib/appdata | tee /backups/app-$(date +%F).tgz | sha256sum)
    echo "checksum: $archive"
}

fetch_manifest() {
    curl -s https://internal.example.com/manifest.json -o /backups/manifest.json
}

if backup; then
    fetch_manifest
    rm -rf /backups/tmp-*
    echo "backup ok"
fi

Anything worth tightening before I forget about it?
